// For each active client: generate the morning summary via the core API
// (which uses NIM/DeepSeek) and Telegram it to the owner.
const http = this.helpers.httpRequest;
const env = (k, d='') => ($env[k] ?? d);
const CORE = env('CORE_API_URL', 'http://127.0.0.1:8003').replace(/\/$/, '');
const TG_TOKEN = env('TELEGRAM_BOT_TOKEN', '');
const KEY = env('LAZUSAI_CORE_KEY', '');
const hdr = { 'X-LazusAI-Key': KEY, 'Content-Type': 'application/json' };

const out = [];
for (const item of $input.all()) {
  const c = item.json;
  if (c.active === false) continue;
  const clientId = c.client_id;
  const cfg = await http({ method: 'GET', url: `${CORE}/clients/${clientId}/config`, headers: hdr, json: true });
  const sum = await http({ method: 'POST', url: `${CORE}/clients/${clientId}/summary`, headers: hdr, body: {}, json: true });
  const chatId = (cfg.owner_telegram || '').replace(/^@/, '');
  const msg = `☀️ *${cfg.business_name}* — Daily Summary\n\n` +
    `💬 Conversations: ${sum.total_conversations}\n` +
    `🎯 Leads: ${sum.leads}\n\n${sum.summary}`;
  if (TG_TOKEN && chatId) {
    await http({ method: 'POST', url: `https://api.telegram.org/bot${TG_TOKEN}/sendMessage`,
      body: { chat_id: chatId, text: msg, parse_mode: 'Markdown' }, json: true });
  }
  out.push({ json: { client_id: clientId, sent: !!(TG_TOKEN && chatId), summary: sum.summary } });
}
return out;
